#!/usr/bin/env python3
r"""
B15a — Prepare Europe wetland/peat source acquisition and web-layer workflow.

Run from repository root:

  python scripts\27_prepare_europe_wetland_peat_workflow.py

This creates documentation and a dependency-free processor script.
It does not download or process raw GIS data.
"""

from pathlib import Path
import datetime

TODAY = datetime.date.today().isoformat()
ACQUISITION_MD = '# B15a — Europe Wetland/Peat Layer Source Acquisition and Staging\n\nDate: 2026-06-18\n\n## Goal\n\nReplace the Europe placeholder in the sticky-scroll story with a real European peat/wetland context layer.\n\n## Recommended source\n\nEuropean Wetland Map / Zenodo.\n\n## Role in the story\n\nThe Europe layer should not be a high-detail analytical layer. It should function as a continental bridge between:\n\n- global/national emissions context,\n- Germany organic-soils layer,\n- Baden-Württemberg BK50-Moor layer.\n\n## Data-handling principle\n\nFor the public website, the Europe layer must be strongly filtered, dissolved and simplified.\n\nDo **not** attempt to publish a full-resolution European wetland product directly as GeoJSON.\n\n## Manual GIS workflow\n\n### 1. Download\n\nDownload the European Wetland Map data.\n\nStore raw files under:\n\n```text\ndata/external/peat_soils/europe_wetland_peat/\n```\n\nDo not commit raw files.\n\n### 2. Inspect\n\nOpen the relevant data in ArcGIS Pro or QGIS.\n\nIdentify:\n\n```text\nclass field\nwetland/peatland category field\nformat\nCRS\nfile size\nextent\n```\n\n### 3. Select/filter classes\n\nFor the sticky-story layer, select only classes relevant to peatland / organic-soil / wetland context.\n\nAvoid using all classes if the result is too broad or too heavy.\n\n### 4. Dissolve\n\nDissolve by the selected class field.\n\nUse multipart features if available.\n\n### 5. Simplify\n\nStart settings:\n\n```text\nAlgorithm:\nRetain critical points / Douglas-Peucker\n\nTolerance:\n2000 Meters\n\nMinimum Area:\n250000 Square Meters\n```\n\nIf still too large:\n\n```text\nTolerance:\n5000 Meters\n\nMinimum Area:\n1000000 Square Meters\n```\n\nThis is acceptable for a continental scrollytelling context layer.\n\n### 6. Export to GeoJSON\n\nExport to:\n\n```text\ndata/external/peat_soils/europe_wetland_peat/europe_peat_wetland_wgs84.geojson\n```\n\nSettings:\n\n```text\nFormat: GeoJSON\nCRS: EPSG:4326 / WGS84\nEncoding: UTF-8\n```\n\nIn ArcGIS Pro:\n\n```text\nFeatures To JSON\nOutput to GeoJSON: checked\nProject to WGS84: checked\nUse field aliases: unchecked\nFormatted JSON: unchecked\n```\n\n### 7. Build web layer\n\nRun:\n\n```powershell\npython scripts\\28_build_europe_peat_wetland_web_layer_from_geojson.py\n```\n\nExpected outputs:\n\n```text\npublic/data/europe_peat_wetland_simplified.geojson\ndata/processed/europe_peat_wetland_summary.csv\ndocs/B15b_europe_peat_wetland_web_layer_method.md\n```\n\n## QA targets\n\n```text\nGeoJSON size: ideal < 8 MB, acceptable < 15 MB\nFeatures: preferably dissolved by class\nLayer purpose: continental spatial context, not site-level analysis\n```\n\n## Interpretation boundary\n\nSuggested atlas caveat:\n\n> This layer shows continental wetland/peat spatial context. It is not a local rewetting suitability map.\n'
PROCESSOR_SCRIPT = '#!/usr/bin/env python3\nr"""\nB15b — Build a web-ready Europe peat/wetland context layer from a GIS-exported GeoJSON.\n\nInput expected:\n  data/external/peat_soils/europe_wetland_peat/europe_peat_wetland_wgs84.geojson\n\nRecommended GIS preparation:\n  1. Download European Wetland Map data.\n  2. Select only peatland / organic-soil / relevant wetland classes for the atlas.\n  3. Dissolve by the selected class field.\n  4. Simplify for continental overview.\n  5. Export to EPSG:4326 GeoJSON.\n\nRun:\n  python scripts\\28_build_europe_peat_wetland_web_layer_from_geojson.py\n\nOutputs:\n  public/data/europe_peat_wetland_simplified.geojson\n  data/processed/europe_peat_wetland_summary.csv\n  docs/B15b_europe_peat_wetland_web_layer_method.md\n\nNo external Python dependencies.\n"""\n\nfrom pathlib import Path\nimport csv\nimport datetime\nimport json\nimport math\n\n\nTODAY = datetime.date.today().isoformat()\n\nINPUT = Path("data/external/peat_soils/europe_wetland_peat/europe_peat_wetland_wgs84.geojson")\nOUTPUT = Path("public/data/europe_peat_wetland_simplified.geojson")\nSUMMARY = Path("data/processed/europe_peat_wetland_summary.csv")\nMETHOD = Path("docs/B15b_europe_peat_wetland_web_layer_method.md")\n\n# Continental overview simplification. Adjust upward if output is still too large.\nSIMPLIFY_TOLERANCE = 0.02\n\nCLASS_CANDIDATES = [\n    "class", "Class", "CLASS", "klasse", "Klasse",\n    "wetland", "Wetland", "wetland_type", "WetlandType", "WETLAND_TYPE",\n    "peatland", "Peatland", "peat_type", "PEAT_TYPE",\n    "category", "Category", "CATEGORY",\n    "type", "Type", "TYPE",\n    "label", "Label", "LABEL",\n    "name", "Name", "NAME",\n    "legend", "Legend", "LEGEND",\n    "gridcode", "GRIDCODE", "code", "Code", "CODE"\n]\n\nAREA_CANDIDATES = [\n    "area_ha", "AREA_HA", "ha", "HA",\n    "area", "Area", "AREA",\n    "Shape_Area", "SHAPE_Area", "shape_area",\n    "Flaeche", "Fläche", "FLAECHE"\n]\n\n\ndef point_line_distance(point, start, end):\n    x, y = point[:2]\n    x1, y1 = start[:2]\n    x2, y2 = end[:2]\n\n    if x1 == x2 and y1 == y2:\n        return math.hypot(x - x1, y - y1)\n\n    num = abs((y2 - y1) * x - (x2 - x1) * y + x2 * y1 - y2 * x1)\n    den = math.hypot(y2 - y1, x2 - x1)\n    return num / den\n\n\ndef douglas_peucker(points, tolerance):\n    if len(points) <= 3:\n        return points\n\n    closed = points[0][:2] == points[-1][:2]\n    work = points[:-1] if closed else points\n\n    if len(work) <= 3:\n        return points\n\n    max_dist = 0\n    index = 0\n    for i in range(1, len(work) - 1):\n        dist = point_line_distance(work[i], work[0], work[-1])\n        if dist > max_dist:\n            max_dist = dist\n            index = i\n\n    if max_dist > tolerance:\n        left = douglas_peucker(work[: index + 1], tolerance)\n        right = douglas_peucker(work[index:], tolerance)\n        result = left[:-1] + right\n    else:\n        result = [work[0], work[-1]]\n\n    if closed:\n        if result[0][:2] != result[-1][:2]:\n            result.append(result[0])\n        if len(result) < 4:\n            return points\n\n    return result\n\n\ndef simplify_geometry(geom, tolerance):\n    if not geom:\n        return geom\n\n    gtype = geom.get("type")\n    coords = geom.get("coordinates")\n\n    if gtype == "Polygon":\n        return {"type": "Polygon", "coordinates": [douglas_peucker(ring, tolerance) for ring in coords]}\n\n    if gtype == "MultiPolygon":\n        return {\n            "type": "MultiPolygon",\n            "coordinates": [\n                [douglas_peucker(ring, tolerance) for ring in poly]\n                for poly in coords\n            ],\n        }\n\n    return geom\n\n\ndef first_existing(props, candidates, default=""):\n    lower_lookup = {str(k).lower(): k for k in props.keys()}\n\n    for key in candidates:\n        if key in props and props.get(key) not in (None, ""):\n            return props.get(key)\n\n    for key in candidates:\n        actual = lower_lookup.get(str(key).lower())\n        if actual is not None and props.get(actual) not in (None, ""):\n            return props.get(actual)\n\n    return default\n\n\ndef numeric(value):\n    if value in (None, ""):\n        return None\n    try:\n        return float(str(value).replace(",", "."))\n    except ValueError:\n        return None\n\n\ndef feature_bbox(geom):\n    xs, ys = [], []\n\n    def visit(obj):\n        if not isinstance(obj, list):\n            return\n        if obj and isinstance(obj[0], (int, float)) and len(obj) >= 2:\n            xs.append(obj[0])\n            ys.append(obj[1])\n        else:\n            for item in obj:\n                visit(item)\n\n    if geom:\n        visit(geom.get("coordinates"))\n\n    if not xs:\n        return None\n\n    return [min(xs), min(ys), max(xs), max(ys)]\n\n\ndef count_vertices(geom):\n    total = 0\n\n    def visit(obj):\n        nonlocal total\n        if not isinstance(obj, list):\n            return\n        if obj and isinstance(obj[0], (int, float)) and len(obj) >= 2:\n            total += 1\n        else:\n            for item in obj:\n                visit(item)\n\n    if geom:\n        visit(geom.get("coordinates"))\n\n    return total\n\n\ndef main():\n    if not INPUT.exists():\n        raise SystemExit(\n            f"Input not found: {INPUT}\\n"\n            "Export a filtered/dissolved/simplified Europe wetland/peat layer as EPSG:4326 GeoJSON first."\n        )\n\n    with INPUT.open("r", encoding="utf-8") as f:\n        geo = json.load(f)\n\n    features = geo.get("features", [])\n    if not features:\n        raise SystemExit("Input GeoJSON has no features.")\n\n    out_features = []\n    summary = {}\n    vertices_before = 0\n    vertices_after = 0\n\n    for feat in features:\n        props = feat.get("properties", {}) or {}\n        klass = str(first_existing(props, CLASS_CANDIDATES, "Peat/wetland context")).strip() or "Peat/wetland context"\n        area_raw = first_existing(props, AREA_CANDIDATES, "")\n        area_num = numeric(area_raw)\n\n        geom_in = feat.get("geometry")\n        vertices_before += count_vertices(geom_in)\n        geom = simplify_geometry(geom_in, SIMPLIFY_TOLERANCE)\n        vertices_after += count_vertices(geom)\n        bbox = feature_bbox(geom)\n\n        summary.setdefault(klass, {"feature_count": 0, "area_sum_raw": 0.0})\n        summary[klass]["feature_count"] += 1\n        if area_num is not None:\n            summary[klass]["area_sum_raw"] += area_num\n\n        new_props = {\n            "class": klass,\n            "source_area": area_raw,\n        }\n\n        if bbox:\n            new_props["bbox"] = bbox\n\n        out_features.append({\n            "type": "Feature",\n            "properties": new_props,\n            "geometry": geom,\n        })\n\n    output_geo = {\n        "type": "FeatureCollection",\n        "name": "europe_peat_wetland_simplified",\n        "metadata": {\n            "title": "Europe peat/wetland simplified web layer",\n            "created": TODAY,\n            "source": "European Wetland Map / user-filtered GIS export",\n            "interpretation": "Continental wetland/peat spatial context layer; not a local rewetting suitability map.",\n            "input": str(INPUT),\n            "simplification_tolerance_degrees": SIMPLIFY_TOLERANCE,\n            "vertices_before": vertices_before,\n            "vertices_after": vertices_after,\n        },\n        "features": out_features,\n    }\n\n    OUTPUT.parent.mkdir(parents=True, exist_ok=True)\n    with OUTPUT.open("w", encoding="utf-8") as f:\n        json.dump(output_geo, f, ensure_ascii=False, separators=(",", ":"))\n\n    SUMMARY.parent.mkdir(parents=True, exist_ok=True)\n    with SUMMARY.open("w", encoding="utf-8", newline="") as f:\n        writer = csv.DictWriter(f, fieldnames=["class", "feature_count", "area_sum_raw"])\n        writer.writeheader()\n        for klass, vals in sorted(summary.items(), key=lambda x: (-x[1]["feature_count"], x[0])):\n            writer.writerow({\n                "class": klass,\n                "feature_count": vals["feature_count"],\n                "area_sum_raw": vals["area_sum_raw"],\n            })\n\n    method = f"""# B15b — Europe Peat/Wetland Web Layer\n\nDate: {TODAY}\n\n## Input\n\n`{INPUT}`\n\nThe input is expected to be a GIS-filtered, dissolved and simplified GeoJSON export of the European Wetland Map or another European peat/wetland context layer.\n\n## Output\n\n`{OUTPUT}`\n\n## Processing\n\n- read input GeoJSON,\n- detect class fields flexibly,\n- retain class and area information where available,\n- apply additional web-only Douglas-Peucker simplification with tolerance `{SIMPLIFY_TOLERANCE}` degrees,\n- export compact GeoJSON for GitHub Pages display,\n- write class summary.\n\n## Vertex reduction\n\n- vertices before Python simplification: {vertices_before}\n- vertices after Python simplification: {vertices_after}\n\n## Interpretation boundary\n\nThis layer is a continental spatial context layer. It is not a local rewetting suitability map and should not be used for site-level planning.\n"""\n\n    METHOD.parent.mkdir(parents=True, exist_ok=True)\n    METHOD.write_text(method, encoding="utf-8")\n\n    size_mb = OUTPUT.stat().st_size / 1024 / 1024\n\n    print("B15b Europe peat/wetland web layer built.")\n    print("Input features:", len(features))\n    print("Output features:", len(out_features))\n    print("Vertices before:", vertices_before)\n    print("Vertices after:", vertices_after)\n    print(f"Output size: {size_mb:.2f} MB")\n    print("Output:", OUTPUT)\n    print("Summary:", SUMMARY)\n    print("Method:", METHOD)\n\n    if size_mb > 15:\n        print()\n        print("WARNING: Output is still larger than 15 MB. Increase GIS simplification or SIMPLIFY_TOLERANCE.")\n\n\nif __name__ == "__main__":\n    main()\n'
TASK = '# Task B15b — Process Europe Wetland/Peat Web Layer\n\n## Agent\n\nData & GIS Agent + Visualization Engineer Agent + QA Critic Agent\n\n## Preconditions\n\n- Europe wetland/peat data has been downloaded manually.\n- Relevant classes have been selected/filterd.\n- The layer has been dissolved and simplified.\n- It has been exported to:\n\n`data/external/peat_soils/europe_wetland_peat/europe_peat_wetland_wgs84.geojson`\n\n## Run\n\n```powershell\npython scripts\\28_build_europe_peat_wetland_web_layer_from_geojson.py\n```\n\n## Expected outputs\n\n- `public/data/europe_peat_wetland_simplified.geojson`\n- `data/processed/europe_peat_wetland_summary.csv`\n- `docs/B15b_europe_peat_wetland_web_layer_method.md`\n\n## QA checks\n\n- output GeoJSON opens in browser,\n- file size is acceptable for GitHub Pages,\n- class field is meaningful,\n- visual distribution is plausible,\n- no raw files under `data/external/` are committed.\n\n## Acceptance criteria\n\n- Europe sticky-story step can use the real layer,\n- source attribution and caveat are documented,\n- layer is clearly labelled as context, not rewetting suitability.\n'

def write(path: Path, text: str):
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(text, encoding="utf-8")

def main():
    root = Path.cwd()
    if not (root / "index.html").exists():
        raise SystemExit("Run from repository root. index.html not found.")

    write(root / "docs" / "B15a_europe_wetland_peat_source_acquisition.md", ACQUISITION_MD)
    write(root / "scripts" / "28_build_europe_peat_wetland_web_layer_from_geojson.py", PROCESSOR_SCRIPT)
    write(root / "tasks" / "B15b_process_europe_wetland_peat_web_layer.md", TASK)

    done = root / "tasks" / "done.md"
    done_text = done.read_text(encoding="utf-8") if done.exists() else "# Done\n"
    if "Task B15a completed" not in done_text:
        done_text += f"- {TODAY}: Task B15a completed — prepared Europe wetland/peat source workflow and web-layer processor.\n"
        write(done, done_text)

    print("B15a Europe wetland/peat workflow prepared.")
    print("Changed/created:")
    print("  docs/B15a_europe_wetland_peat_source_acquisition.md")
    print("  scripts/28_build_europe_peat_wetland_web_layer_from_geojson.py")
    print("  tasks/B15b_process_europe_wetland_peat_web_layer.md")
    print("  tasks/done.md")
    print()
    print("Next:")
    print("  Download/process the Europe layer manually in GIS, then run script 28.")

if __name__ == "__main__":
    main()
